<script setup>
import { ref, computed, onMounted, watch } from 'vue'
import axios from 'axios'

const data = ref({
  basic: {
    siteName: 'ねこの庭',
    siteNameSub: 'neko no niwa',
    ownerName: 'みずき · Mizuki',
    ownerSubtitle: 'illustrator · dreamer · cat person',
    bio: '喜欢画画、喝茶和发呆。\n世界很大，我只想做一个安静的人。',
    bioSub: '— 在某个不知名的角落创作着 —',
    statusText: '目前在画春天的猫咪系列 · currently drawing spring cats',
    quoteText: '生活不必轰轰烈烈，\n有一杯热茶、一只猫、一个安静的下午，\n就已经足够好了。',
    quoteAttr: '— みずき の手记',
    footerSocial: 'ins: @mizuki_neko · pixiv: mizukineko · mail: hello@mizukineko.com',
    footerMadeBy: 'made with ♡ by みずき',
    seoTitle: '',
    seoKeywords: '',
    seoDescription: '',
    seoSubtitle: ''
  },
  tags: [],
  socials: [],
  aboutBoxes: [],
  diary: [],
  playlist: [],
  friends: [],
  sectionVisibility: { about: true, diary: true, playlist: true, friends: true }
})

const heroName = computed(() => {
  const parts = data.value.basic?.ownerName?.split('·') || []
  if (parts.length > 1) {
    return `${parts[0]}<span class="accent">·</span>${parts[1]}`
  }
  return data.value.basic?.ownerName || ''
})

const bioHtml = computed(() => {
  const bio = data.value.basic?.bio?.replace(/\n/g, '<br>') || ''
  const bioSub = data.value.basic?.bioSub || ''
  return `${bio}<br><span style="font-size:.8em;color:var(--ink-faint);">${bioSub}</span>`
})

const footerMadeBy = computed(() => {
  return data.value.basic?.footerMadeBy?.replace('♡', '<span class="heart">♡</span>') || ''
})

// 更新 SEO 标签
function updateSeo() {
  const basic = data.value.basic || {}
  const seoTitle = basic.seoTitle || basic.siteName || 'ねこの庭'
  const seoSubtitle = basic.seoSubtitle || ''
  const title = seoSubtitle ? `${seoTitle} | ${seoSubtitle}` : seoTitle

  document.title = title

  let metaDescription = document.querySelector('meta[name="description"]')
  if (!metaDescription) {
    metaDescription = document.createElement('meta')
    metaDescription.name = 'description'
    document.head.appendChild(metaDescription)
  }
  metaDescription.content = basic.seoDescription || basic.bio || ''

  let metaKeywords = document.querySelector('meta[name="keywords"]')
  if (!metaKeywords) {
    metaKeywords = document.createElement('meta')
    metaKeywords.name = 'keywords'
    document.head.appendChild(metaKeywords)
  }
  metaKeywords.content = basic.seoKeywords || ''
}

onMounted(async () => {
  try {
    const res = await axios.get('/api/data')
    data.value = res.data
    updateSeo()
  } catch (err) {
    console.error('Failed to load data:', err)
  }
})
</script>
